cardCss:
/*
 * DEATH NOTE
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : The Death Note — matte black leather cover (front) /
 *             Japanese genkouyoshi manuscript paper (back)
 * Fonts     : Cinzel (front, embossed gravitas) · Caveat (back, handwriting)
 * Palette   : Front: #0a0a0a near-black · #ffffff white
 *             Back:  #f5f0e8 aged cream · #1a1a1a pencil · #b8a89a rule-lines
 * Background: Front: near-black base + SVG feTurbulence/feSpecularLighting
 *             leather grain at azimuth 225° elevation 15°
 *             Back:  repeating-linear-gradient ruled lines (every 2rem)
 * Images    : Front: brightness(0.6) contrast(1.2) grayscale(0.3)
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700;900&family=Caveat:wght@400;700&display=swap");
/* term/reading font: Zen Kurenaido (chosen). Also tested: Klee One, Yuji Syuku, Yomogi */
@import url("https://fonts.googleapis.com/css2?family=Zen+Kurenaido&display=swap");

:root {
  --dn-black:  #0a0a0a;
  --dn-white:  #ffffff;
  --dn-cream:  #f5f0e8;
  --dn-pencil: #1a1a1a;
  --dn-rule:   #b8a89a;
  --dn-sepia:  #7a5a40;
}

html, body, div#qa { height: 100%; }

.card { background: var(--dn-black); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.dn-card {
  min-height: 100%;
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  overflow: hidden;
  box-sizing: border-box;
}

/* ── FRONT: LEATHER COVER ── */
.dn-front { background: var(--dn-black); }

.dn-leather-texture {
  position: absolute;
  inset: 0;
  background: #0a0a0a;
  filter: url(#dn-leather);
  pointer-events: none;
  z-index: 0;
}

.dn-content {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 3rem 2.5rem;
  width: 100%;
  box-sizing: border-box;
}

.dn-label {
  font-family: "Cinzel", serif;
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.45em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.3);
  margin: 0 0 2rem;
}

.dn-prompt {
  font-family: "Cinzel", serif;
  font-size: 1.4rem;
  color: rgba(255,255,255,0.6);
  letter-spacing: 0.1em;
  margin: 0 0 1.5rem;
}

.dn-input-wrap { width: 100%; max-width: 28rem; }

.dn-input-wrap input {
  font-family: "Cinzel", serif;
  font-size: 1.4rem;
  background: transparent;
  border: none;
  border-bottom: 1px solid rgba(255,255,255,0.2);
  color: var(--dn-white);
  width: 100%;
  padding: 0.5rem 0;
  text-align: center;
  letter-spacing: 0.08em;
}

.dn-input-wrap input:focus {
  outline: none;
  border-bottom-color: rgba(255,255,255,0.55);
}

.dn-hint-wrap { margin-top: 1.2rem; }

.dn-hint-link {
  font-family: "Cinzel", serif;
  font-size: 0.85rem;
  color: rgba(255,255,255,0.28);
  text-decoration: underline;
  letter-spacing: 0.06em;
}

.dn-hint-text {
  font-family: "Cinzel", serif;
  font-size: 1rem;
  color: rgba(255,255,255,0.45);
  margin-top: 0.5rem;
}

.dn-audio { margin: 0 0 1rem; }

/* ── BACK: GENKOUYOSHI PAPER ── */
.dn-back { background: var(--dn-cream); align-items: flex-start; }

.dn-paper-lines {
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    to bottom,
    transparent,
    transparent calc(2rem - 1px),
    var(--dn-rule) 1px
  );
  opacity: 0.45;
  pointer-events: none;
  z-index: 0;
}

.dn-back-content {
  position: relative;
  z-index: 1;
  padding: 2rem 2.5rem;
  width: 100%;
  box-sizing: border-box;
}

.dn-term {
  font-family: "Zen Kurenaido", cursive;
  font-size: 3.5rem;
  font-weight: 700;
  color: var(--dn-pencil);
  margin: 0 0 0.5rem;
  letter-spacing: -0.01em;
  word-spacing: 0.05em;
}

.dn-reading {
  font-family: "Zen Kurenaido", cursive;
  font-size: 2rem;
  color: var(--dn-sepia);
  margin: 0 0 0.3rem;
}

.dn-translation {
  font-family: "Caveat", cursive;
  font-size: 3.6rem;
  color: var(--dn-pencil);
  opacity: 0.8;
  margin: 0 0 0.3rem;
}

.dn-transliteration {
  font-family: "Caveat", cursive;
  font-size: 3rem;
  color: var(--dn-sepia);
  opacity: 0.65;
  font-style: italic;
  margin: 0 0 0.3rem;
}

.dn-tags {
  font-family: "Caveat", cursive;
  font-size: 2.4rem;
  color: var(--dn-sepia);
  opacity: 0.55;
  margin: 0.5rem 0;
}

.dn-picture img {
  max-width: 100%;
  filter: sepia(0.15) contrast(1.1);
}

.dn-front .dn-picture img {
  filter: brightness(0.6) contrast(1.2) grayscale(0.3);
}

.append-play-btn-text a::after { content: "▶"; }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; }
